// 1. Extract LLM Data from the direct input wire
const aiData = $input.first().json;

// 2. Fetch the Full Source News Pool from workflow history (Limit1)
let newsPool = [];
try {
  // Because Limit1 is a parent of this node's path, we can look it up safely
  const rawLimitItems = $('Limit1').all();
  newsPool = rawLimitItems.map(item => item.json);
} catch (e) {
  // Safe extraction of the error message for TypeScript / modern JS runtimes
  const errorMessage = e instanceof Error ? e.message : String(e);
  return [{ json: { error: "Could not find Limit1 in the execution history.", details: errorMessage } }];
}

// 3. Extract the array indices safely from the LLM
let finalIndices = [];
const potentialInput = aiData.output || aiData.text || aiData.selected_indices || aiData;

if (Array.isArray(potentialInput)) {
  finalIndices = potentialInput.map(i => parseInt(String(i), 10));
} else if (typeof potentialInput === 'string') {
  const match = potentialInput.match(/\[[\s\d,]*\]/);
  if (match) { 
    try { finalIndices = JSON.parse(match[0]); } catch(e){} 
  }
} else if (typeof potentialInput === 'object') {
  const match = JSON.stringify(potentialInput).match(/\[[\s\d,]*\]/);
  if (match) { 
    try { finalIndices = JSON.parse(match[0]); } catch(e){} 
  }
}

// 4. Map the indices back to the Limit1 articles and strip metadata
const curatedNews = finalIndices
  .map(i => {
    const idx = parseInt(String(i), 10);
    const rawArticle = newsPool[idx];

    if (!rawArticle) return null;

    // Handle standard structural nesting safely
    const target = rawArticle.json ? rawArticle.json : rawArticle;

    return {
      title: target.title || "",
      date: target.pubDate || target.isoDate || target.date || "",
      link: target.link || "",
      categories: target.categories || target.category || [],
      source: target.source_name || target.creator || ""
    };
  })
  .filter(item => !!item && item.title !== "");

// 5. Stable Clean Output Logic
if (curatedNews.length > 0) {
  return curatedNews.map(item => ({ json: item }));
} else {
  return [{ 
    json: { 
      status: "empty", 
      message: "Zero articles passed the high-signal tech criteria today.",
      _debug_indices: finalIndices,
      _debug_pool_size: newsPool.length
    } 
  }]; 
}
